// Robust JSON extraction from AI agent output
const rawOutput = $input.first().json.output;

// Try direct parse first
try {
  return JSON.parse(rawOutput);
} catch (e1) {
  // Try stripping markdown code fences
  const cleaned = rawOutput
    .replace(/^```(?:json)?\s*\n?/i, '')
    .replace(/\n?```\s*$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e2) {
    // Try extracting JSON object from text
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        return JSON.parse(jsonMatch[0]);
      } catch (e3) {
        throw new Error(`Failed to parse AI output as JSON. Raw (first 500 chars): ${rawOutput.substring(0, 500)}`);
      }
    }
    throw new Error(`No JSON object found in AI output. Raw (first 500 chars): ${rawOutput.substring(0, 500)}`);
  }
}

