=Extract the products from the attachment.

Keep only the products sepcified in the email content.

Return only valid JSON.
Do not include explanations, markdown, code fences, or any text outside the JSON.

Input:
- attachment: {{ $json.attachementData }}
- email_content: {{ $json.email_content }}
- sender_name: {{ $json.sender_name }}
- email_subject: {{ $json.email_subject }}
- email_received_date: {{ $json.date }}
- email_sender: {{ $json.email_sender }}

parameters.jsCode:
const emailData = new Map() 

if ($input.first().binary) {
  const attachmentsBinary = [];
  const attachments = Object.values($input.first().binary);
  for (const attachment of attachments) {
    attachmentsBinary.push({json:attachment});
  }
  emailData['binary'] = attachmentsBinary;
}else {
  emailData['attachementData'] = 'N/A'
}

emailData['email_content'] = $input.first().json.text;
emailData['date'] = $input.first().json.date;
emailData['sender_name'] = $input.first().json.from.value[0].name;
emailData['email_sender'] = $input.first().json.from.value[0].address;
emailData['email_subject'] = $input.first().json.subject;

return emailData;

let attachementData = '';
for(const pdf of $input.first().json.pdf) {
  attachementData += `--------------------- DATA FROM PDF FILE ${pdf.fileName} --------------------------- \n`
  attachementData += pdf.text
  attachementData += `-------------------------------------------------------------------------- \n\n`
}

for(const xlsx of $input.first().json.xlsx){
  attachementData += `--------------------- DATA FROM XLSX FILE --------------------------- \n`
  attachementData += JSON.stringify(xlsx)
  attachementData += `-------------------------------------------------------------------------- \n\n`
}


return {
  json:{
    attachementData
  }
};
